INSERT INTO "current_ai_summary" ("id", "week_start", "summary", "reports_analyzed", "generated_at") VALUES ('1126f908-e336-459d-ad24-f4ad80b68bad', '2025-12-01', '{"team":{"teamSummary":"The overall feedback from team members reflects a positive morale, with notable achievements in project execution and individual performances. High commendations were received for several members, particularly in handling community management and project reporting. Consistent praise for Shawn McAdam in affiliate engagement and for Andrew Wilshere''s timely reporting suggests these are key strengths in the team. However, while the positive remarks dominate, there''s a hint of concern regarding some members potentially feeling undervalued, necessitating recognition and support.","teamConcerns":[],"supportNeeded":[{"area":"Feedback mechanisms","members":["Hanish Reddy","Erika Bornman"],"suggestedSupport":"Encourage structured feedback processes to foster self-reflection and team collaboration."}],"retentionRisks":[{"members":["Salum Al-Amin","Shawn McAdam"],"indicator":"Concerns about team cohesion and recognition","recommendedAction":"Implement regular team check-ins to gather feedback and ensure all team members feel valuable."}],"teamHighlights":[{"project":"Camping World","highlight":"Outstanding observation and issue management within the community.","memberName":"Jose Bautista"},{"project":"STMicroelectro Community Management","highlight":"Performance is at or above the previous advisor in key areas.","memberName":"Andrew Wilshere"},{"project":"ExxonMobil - Community Management","highlight":"Exceptional skills in managing affiliate engagements and writing engagement copies.","memberName":"Shawn McAdam"},{"project":"Astellas","highlight":"Delivered impressive Q2 report analysis, greatly appreciated by the customer.","memberName":"Shivam Verma"},{"project":"Meta Horizons","highlight":"Demonstrates keen attention to detail during moderation.","memberName":"Christelle Mhanna"},{"project":"Takeda Netherlands","highlight":"Recognized for her dependability.","memberName":"Priscilla Bos"}],"overallTeamMorale":"positive","recommendedHRActions":[{"action":"Create a formal recognition program to celebrate individual and team achievements.","priority":"high","rationale":"This will enhance morale and encourage ongoing high performance, fostering a more cohesive team environment."}],"workloadObservations":[],"developmentOpportunities":[],"recognitionOpportunities":[{"project":"Meta Regional Comms","memberName":"Shawn McAdam","achievement":"Innovative moderation comments appreciated by the team.","suggestedRecognition":"Public shoutout during the next team meeting."},{"project":"Astellas","memberName":"Shivam Verma","achievement":"Impressive analysis of the Q2 report praised by the client.","suggestedRecognition":"Nomination for ''Employee of the Month''."},{"project":"Meta Horizons","memberName":"Andrew Wilshere","achievement":"Consistently delivers reports on time.","suggestedRecognition":"Highlight in the company''s monthly newsletter."}]},"leadership":{"overallHealth":"needs-attention","upcomingFocus":[{"focus":"Monitor ongoing instructions from Odilon Sconieckzny.","project":"Meta Design","priority":"high"},{"focus":"Conduct the bi-weekly meeting and clarify action points.","project":"Visible","priority":"high"},{"focus":"Prepare for project churn and mitigate transition impacts.","project":"O2","priority":"high"},{"focus":"Follow up with leadership for decisions on Client Success Points.","project":"Bunnings Moderation","priority":"medium"}],"weekHighlights":["Executive leadership engaged positively with clients like ExxonMobil and Bunnings, highlighting team achievements in deliverable standards.","Successful onboarding of new resources across multiple projects, enhancing overall project health metrics.","Positive feedback from eBay regarding moderation quality signifies strong operational performance despite staffing changes."],"keyAchievements":[{"impact":"Progress towards overall project health; facilitates timely reporting for upcoming deliverables.","project":"ExxonMobil - Global Listening","achievement":"Monthly checkpoint completed, with enablement processes unblocked."},{"impact":"Improves alignment and responsiveness to client needs, demonstrating adaptability.","project":"Meta Quest CM","achievement":"Renewal proposal documents reviewed and shift timings adjusted per customer expectations."},{"impact":"Enhanced customer engagement through structured moderation efforts.","project":"IG Brand Campaigns","achievement":"Campaign assets properly set up on Khoros Care."}],"executiveSummary":"This week, the portfolio reflects an urgent need for attention with 12 projects marked critical or at-risk, primarily driven by issues like anticipated contract terminations and unresolved escalations. Projects such as UK Post Office and National Instruments require immediate strategic interventions due to their critical health status. While 24 projects maintain an ''on-track'' status, there is a pressing challenge with projects experiencing lackluster activity, particularly Meta Design and Visible, leading to potential risks in deliverable timelines. Leadership should prioritize discussions on renewal strategies and resource management to mitigate risks identified in the critical and at-risk projects.","crossProjectPatterns":{"processIssues":["Delays in reporting and communication regarding contract renewals impacting operational continuity."],"commonChallenges":["Multiple projects facing impending contract terminations, causing uncertainty in planning.","Recurring issues with customer escalations, notably regarding Success Points and API integrations."],"resourceConstraints":["Several projects have indicated staffing concerns affecting their ability to deliver results, particularly in projects with recent resignations."]},"portfolioHealthBreakdown":{"onTrack":{"count":24,"projects":["Camping World (Graice) - Hanish Reddy","Roundel/Target (Tanya García-Patton) - Juan Felipe Sánchez Rocha","ING Bank Slask Best Practice Advisory Services - Community (ING Bank Slaski) - Shalom Dickson","Lansweeper Moderation (Lansweeper) - Shalom Dickson","Comdirect Advisory (Comdirect) - Tuna Yılmaz","STMicroelectro Community Management (STMicroelectronics) - Shalom Dickson","Telenet N.V. Best Practice Advisory Services - Community (Telenet N.V.) - Shalom Dickson","Far Isaac Cor Moderation (MyFico) (Fair Isaac Corporation) - Shalom Dickson","ExxonMobil - Global Listening (Sergey Vishnevsky) - Aamir Saeeduddin","The Venetian Casino and Resort (Claudia Guerrero) - Aamir Saeeduddin","IG Brand Campaigns (Michelle) - Hanish Reddy","ExxonMobil - Community Management (Mike) - Hanish Reddy","CyberSource (CyberSource) - Tuna Yılmaz","British Teleco Moderation (EE) (British Telecommunications plc) - Shalom Dickson","Lithium Technologies, Inc. (Lucy) - Shalom Dickson","Bombardier Rec Best Practice Advisory Services (Bombardier (BRP)) - Arvind Dhanasekaran","Bombardier Rec Moderation (Bombardier (BRP)) - Arvind Dhanasekaran","Bombardier Rec Community Administration (Bombardier (BRP)) - Arvind Dhanasekaran","Atlassian Moderation (Atlassian) - Arvind Dhanasekaran","eBay Moderation: UK (eBay) - Arvind Dhanasekaran","eBay Moderation: AU (eBay) - Arvind Dhanasekaran","eBay Moderation: IN (Exports) (eBay) - Arvind Dhanasekaran","Meta Quest CM (Meta) - Arvind Dhanasekaran","SKY UK (chloe) - Hanish Reddy","Meta Verified (Louis) - Hanish Reddy"]},"critical":{"count":12,"projects":["UK Post Office (Post Office ltd.) - David Fried: Offboarding processes initiated.","Bunnings Moderation (Bunnings) - Arvind Dhanasekaran: Escalation of Success Points unresolved.","National Instruments (Daril González de León) - Juan Felipe Sánchez Rocha: Contract termination letter received.","O2 (Virgin Media) - Tuna Yılmaz: Project likely to churn by January 2026.","Meta Public Affairs (Erin Baltazar) - Erika Bornman: Contract renewal status unclear as it ends on 12/31.","Meta Design (Unknown) - Juan Felipe Sánchez Rocha: No activity since acquisition.","Visible (Verizon) - Tuna Yılmaz: Delay in follow-up actions or feedback.","Verizon Community Moderation (Verizon) - Arvind Dhanasekaran: Lack of clarity on contract direction.","Sephora Community Administration (Sephora) - Arvind Dhanasekaran: API issues impacting operations.","PTC Therapeutics (Cherilyn Quizan) - Erika Bornman: Uncertain renewal outcomes.","Verizon Community Administration (Verizon) - Arvind Dhanasekaran: Workflow planning uncertain prior to renewal.","Lansweeper Moderation (Lansweeper) - Shalom Dickson: Ongoing risk with unclear escalation."]},"needsAttention":{"count":15,"projects":["Meta Design (Unknown) - Juan Felipe Sánchez Rocha: Project with no activity since Khoros acquisition.","Visible (Verizon) - Tuna Yılmaz: Awaiting follow-up actions or feedback from Visible.","Verizon Community Moderation (Verizon) - Arvind Dhanasekaran: Pending clarity on contract direction.","O2 (Virgin Media) - Tuna Yılmaz: No moderation possible due to issues on the client''s side.","ExxonMobil - Community Management (Mike) - Hanish Reddy: LinkedIn on care needs to be reconnected.","Johnson & Johnson Corp (Keith Miles) - Erika Bornman: Contract ending on 12/31; needs review for data retention.","PTC Therapeutics (Cherilyn Quizan) - Erika Bornman: Renewal negotiations ongoing.","Meta Public Affairs (Erin Baltazar) - Erika Bornman: Awaiting POC on contract renewal.","Sephora Community Administration (Sephora) - Arvind Dhanasekaran: Technical issues requiring fixes.","National Instruments (Daril González de León) - Juan Felipe Sánchez Rocha: Anticipated contract termination by March 3, 2026.","Bunnings Moderation (Bunnings) - Arvind Dhanasekaran: Success Points escalation pending review.","Sinch UK Best Practice Advisory Services - Community (Sinch UK) - Shalom Dickson: Client pressures to switch vendors.","Verizon Community Administration (Verizon) - Arvind Dhanasekaran: Uncertain renewal direction.","Meta VR Forum Moderation (Meta) - Arvind Dhanasekaran: Technical issues with deleted-content monitored.","Meta Waba Mexico (Renata Cardoso Laudisio) - Juan Felipe Sánchez Rocha: Project completion pending this week."]}},"immediateAttentionRequired":[{"lead":"David Fried","issue":"Offboarding processes initiated, indicating project termination.","project":"UK Post Office","customer":"Post Office ltd.","recommendedAction":"Immediate strategic discussions to transition resources and wrap up deliverables."},{"lead":"Juan Felipe Sánchez Rocha","issue":"Anticipated contract termination has been communicated, with significant implications for planning.","project":"National Instruments","customer":"Daril González de León","recommendedAction":"Engage with the customer to clarify the reasons for termination and assess potential retention strategies."},{"lead":"Arvind Dhanasekaran","issue":"Escalation regarding Success Points usage unresolved, impacting client relationships.","project":"Bunnings Moderation","customer":"Bunnings","recommendedAction":"Prioritize resolution discussions with leadership to clarify client expectations and potential impacts."},{"lead":"Tuna Yılmaz","issue":"Project set to terminate by January 2026 due to ongoing issues.","project":"O2","customer":"Virgin Media","recommendedAction":"Assess mitigation strategies to manage client churn and transition."},{"lead":"Juan Felipe Sánchez Rocha","issue":"Complete inactivity since acquisition poses risks to future partnerships.","project":"Meta Design","customer":"Unknown","recommendedAction":"Reevaluate project viability and consider potential reallocation of resources."}],"recommendedLeadershipActions":[{"action":"Initiate strategic discussions with critical customers experiencing termination notices.","priority":"high","rationale":"To identify potential retention strategies or clarify internal challenges affecting their contracts."},{"action":"Secure more robust processes for tracking project statuses and customer escalations.","priority":"medium","rationale":"Improve visibility and response times leading to better client relationship management."},{"action":"Reassess resource allocation, especially after resignations that are impacting several projects.","priority":"high","rationale":"To ensure all projects are adequately staffed and can meet their deliverables."}]}}', '51', '2025-12-10T09:54:26.450472') ON CONFLICT DO NOTHING;
INSERT INTO "current_ai_summary" ("id", "week_start", "summary", "reports_analyzed", "generated_at") VALUES ('b1b5273b-75f0-46fb-8203-44f6a2351663', '2026-01-26', '{"team":null,"leadership":{"overallHealth":"needs-attention","upcomingFocus":[{"focus":"Resolve analytics report delays and conduct normal community moderation.","project":"Fair Isaac Corporation","priority":"high"},{"focus":"Attempt completion of weekly reports after analytics resolution.","project":"Meta Horizons","priority":"high"}],"weekHighlights":["Successful QBR for Takeda reinforces compliance tracking and customer relationship.","Ongoing moderation efforts for eBay projects demonstrate steady client satisfaction and operational efficiency."],"keyAchievements":[{"impact":"Supports client''s strategic overview and engaging with stakeholders.","project":"Telenet N.V.","achievement":"Preparing annual report successfully."},{"impact":"Strengthens client relationship and offers insight into compliance procedures.","project":"Takeda","achievement":"Successful QBR conducted."}],"executiveSummary":"The portfolio health is currently categorized as ''needs-attention'' due to emerging concerns, specifically with projects like National Instruments and Fair Isaac Corporation facing access issues and report delays. While the majority of projects remain on track, significant risks in critical projects, including Meta Horizons, have surfaced this week due to unresolved analytics failures impacting reporting capabilities. Additionally, projects such as Lansweeper and Takeda have demonstrated steady progress but must be closely monitored for continued engagement. The need for targeted interventions to support at-risk projects is imperative to maintain overall portfolio stability.","weekOverWeekChanges":{"improved":["Most projects maintained an on-track status with steady progress, including eBay projects and Telenet N.V., demonstrating consistent operational stability."],"newRisks":["The inability to generate weekly reports for Meta Horizons presents a significant risk affecting customer deliverables."],"resolved":["No specific issues were reported as resolved this week."],"worsened":["Meta Horizons reported critical delays due to unresolved analytics errors preventing weekly report generation, escalating concerns from last week."]},"crossProjectPatterns":{"processIssues":["Client unresponsiveness causing delays in critical decisions."],"commonChallenges":["Ongoing access and analytics issues affecting multiple projects, notably Meta Horizons and National Instruments."],"resourceConstraints":["Notable capacity limitations impacting moderation across several projects."]},"portfolioHealthBreakdown":{"onTrack":{"count":20,"projects":["eBay US, EMEA, CA, CA-FR (Valeri Yee) – Tuna Yılmaz: Progressing well with consistent moderation.","CyberSource (Poornima Jagannath) – Tuna Yılmaz: Regular moderation ongoing.","Sephora Community Administration (Carol Rooney) – Arvind Dhanasekaran: Administrative transition underway.","eBay Moderation: IN (Exports) (Maja Yllor Martin) – Arvind Dhanasekaran: Normal operations with EOW report delivery.","Telenet N.V. (Suzy Vranken) – Erika Bornman: Year-on-year report preparation ongoing.","Astellas (Bob) – Hanish Reddy: Q3 report work in progress.","Orange France (ibtiseme) – Hanish Reddy: Migration of reports successfully completed.","British Telecommunications (EE) (James Brigham) – Hanish Reddy: Consistent moderation and reporting.","Meta Community Administration (Marlowe) – Hanish Reddy: Normal operations, no action required.","Takeda (Stephanie Obara) – Shaikh Abdul: Successful QBR and ongoing social listening.","Bunnings Moderation (Jason Hill) – Arvind Dhanasekaran: Ongoing moderation with extra coverage.","Atlassian Moderation (Kate Clark) – Arvind Dhanasekaran: Active moderation and report management.","eBay Moderation: UK (David McMullen) – Arvind Dhanasekaran: Daily topics and community management in place.","eBay Moderation: AU (Sandra Raskovska) – Arvind Dhanasekaran: Weekly report deliveries on track.","Takeda Netherlands (Marijke Alleman) – Erika Bornman: Ongoing healthy relationships with clients.","SKY UK (chloe) – Hanish Reddy: Data export completed for metrics.","ExxonMobil - Community Management (Mike) – Hanish Reddy: Brand mentions managed effectively.","Airbnb (tbc) – Arvind Dhanasekaran: Active development and customer engagement.","STMicroelectronics (Amelie Ackermann) – Erika Bornman: Regular customer engagement and issue resolution.","Sinch UK (Shahzad Ismail) – Hanish Reddy: No actions required, maintaining status quo.","Camping World (Graice) – Hanish Reddy: Weekly report delivered, customer call postponed."]},"critical":{"count":1,"projects":["Meta Horizons (Marlowe) – Hanish Reddy: Critical reporting issues due to unresolved analytics errors."]},"needsAttention":{"count":3,"projects":["Lansweeper (Cassandra LLyod) – Timilehin Adetayo: Report preparation in progress; needs monitoring.","Fair Isaac Corporation (Britney Chamberlin) – Erika Bornman: Analytics issue delaying reports.","National Instruments (Daril González de León) – Shaikh Abdul: Access issues complicating report generation."]}},"immediateAttentionRequired":[{"lead":"Hanish Reddy","issue":"Reporting blocked by analytics failures.","project":"Meta Horizons","customer":"Marlowe","recommendedAction":"Escalate analytics support issues to ensure timely reporting capabilities are restored."},{"lead":"Shaikh Abdul","issue":"Loss of access to critical files due to Google workspace migration.","project":"National Instruments","customer":"Daril González de León","recommendedAction":"Follow up with IT on support ticket to resolve access issues promptly."}],"recommendedLeadershipActions":[{"action":"Prioritize resolution of analytics and access support tickets.","priority":"high","rationale":"Delays are critically impacting project performance across multiple clients."}],"dependenciesAndCrossTeamNeeds":[{"impact":"Critical for meeting reporting deadlines and maintaining client trust.","project":"Meta Horizons","dependency":"Resolution of analytics support tickets","requiredSupport":"Escalation to IT or analytics team for expedited resolution."},{"impact":"Delays report generation and overall project efficacy.","project":"National Instruments","dependency":"Access to shared drives","requiredSupport":"Ensure IT resolves ticket for immediate access restoration."}]}}', '28', '2026-02-04T07:18:30.10121') ON CONFLICT DO NOTHING;
INSERT INTO "current_ai_summary" ("id", "week_start", "summary", "reports_analyzed", "generated_at") VALUES ('46078466-a68b-4c70-a4fb-d3c724b3a42f', '2026-03-16', '{"team":null,"leadership":{"overallHealth":"needs-attention","upcomingFocus":[{"focus":"Monitor emerging geopolitical risks and sentiment shifts.","project":"ExxonMobil - Community Management","priority":"high"},{"focus":"Clarify access issues and engagement strategies.","project":"Airbnb","priority":"high"},{"focus":"Follow up on customer satisfaction and urgent ticket resolutions.","project":"STMicroelectronics","priority":"medium"}],"weekHighlights":["Successful delivery of Exxon Tik-Tok Pulse reports without major flags.","Completion of bi-weekly moderation reports for multiple eBay regions maintained service quality and transparency."],"keyAchievements":[{"impact":"Improves brand responsiveness and enhances user engagement quality.","project":"ExxonMobil - Community Management","achievement":"Cleared all brand mention queues daily, reducing backlog to zero."},{"impact":"Enhances transparency and community health through rigorous moderation practices.","project":"eBay US, EMEA, CA, CA-FR","achievement":"Managed over 1,600 posts QAed successfully."}],"executiveSummary":"The portfolio contains 18 on-track projects, indicating strong overall activity; however, two projects are critical, notably STMicroelectronics and its unresolved support tickets that are affecting customer satisfaction. Airbnb continues to show at-risk indicators due to challenges with engagement strategy. Despite emerging issues, there are also positive developments, including timely report deliveries across various projects, which enhance overall transparency. Immediate attention is required to resolve the issues to prevent further deterioration of project health and client relationships.","weekOverWeekChanges":{"improved":["ExxonMobil - Global Listening (Sergey Vishnevsky – Hanish Reddy) maintained strong reporting and monitoring practices with no major flags detected.","eBay US, EMEA, CA, CA-FR (Valeri Yee – Tuna Yılmaz) consistently handled high volume QA activities, maintaining community quality."],"newRisks":["Meta Quest CM (Ryan Goddard – Arvind Dhanasekaran) faces risks regarding renewal confirmation, creating uncertainty around engagement."],"resolved":["No specific issues were reported as resolved this week."],"worsened":["STMicroelectronics (Amelie Ackermann – Erika Bornman) has escalated as critical due to persistent unresolved support tickets and growing customer dissatisfaction.","British Telecommunications (EE) (James Brigham – Hanish Reddy) is now at-risk due to an analytics data issue affecting report completeness."]},"crossProjectPatterns":{"processIssues":["Inconsistent handling of analytics issues across various teams causing reporting backlogs."],"commonChallenges":["Several projects experiencing unresolved support issues affecting customer satisfaction.","Emerging reputational risks highlighting the need for vigilant monitoring across communities."],"resourceConstraints":["Noted increased staffing needs in community moderation affecting response times."]},"portfolioHealthBreakdown":{"onTrack":{"count":18,"projects":["CyberSource (Poornima Jagannath) – Tuna Yılmaz: on-track","Comdirect Advisory (Christoph Kummer) – Tuna Yılmaz: on-track","Orange France (ibtiseme) – Hanish Reddy: on-track","Sinch UK (Shahzad Ismail) – Hanish Reddy: on-track","Camping World (Graice) – Hanish Reddy: on-track","ExxonMobil - Global Listening (Sergey Vishnevsky) – Hanish Reddy: on-track","Fair Isaac Corporation (Britney Chamberlin) – Erika Bornman: on-track","eBay US, EMEA, CA, CA-FR (Valeri Yee) – Tuna Yılmaz: on-track","Meta VR Forum Moderation (Kevin Burns) – Arvind Dhanasekaran: on-track","Astellas (Bob) – Hanish Reddy: on-track","ING Bank Slaski (Joanna Pietka) – Erika Bornman: on-track","Takeda Netherlands (Marijke Alleman) – Erika Bornman: on-track","Telenet N.V. (Suzy Vranken) – Erika Bornman: on-track","SKY UK (chloe) – Hanish Reddy: on-track","eBay Moderation: AU (Sandra Raskovska) – Arvind Dhanasekaran: on-track","eBay Moderation: UK (David McMullen) – Arvind Dhanasekaran: on-track","Meta Community Administration (Marlowe) – Arvind Dhanasekaran: on-track","eBay Moderation: IN (Exports) (Maja Yllor Martin) – Arvind Dhanasekaran: on-track"]},"critical":{"count":2,"projects":["STMicroelectronics (Amelie Ackermann) – Erika Bornman: unresolved support tickets impacting customer satisfaction.","British Telecommunications (EE) (James Brigham) – Hanish Reddy: Analytics data issue affecting reporting."]},"needsAttention":{"count":1,"projects":["Airbnb (tbc) – Arvind Dhanasekaran: at-risk engagement strategies."]}},"immediateAttentionRequired":[{"lead":"Erika Bornman","issue":"Multiple unresolved support tickets leading to customer frustration.","project":"STMicroelectronics","customer":"Amelie Ackermann","recommendedAction":"Prioritize resolution of outstanding tickets with the engineering team to restore customer confidence."},{"lead":"Hanish Reddy","issue":"Analytics data issue affecting report completeness and overall reporting accuracy.","project":"British Telecommunications (EE)","customer":"James Brigham","recommendedAction":"Collaborate with the analytics team to address the data access issue and ensure accurate delivery of reports."},{"lead":"Arvind Dhanasekaran","issue":"Engagement strategy facing at-risk conditions.","project":"Airbnb","customer":"tbc","recommendedAction":"Develop a focused strategy to enhance customer engagement and clarify expectations as soon as possible."}],"recommendedLeadershipActions":[{"action":"Address ongoing support issues in STMicroelectronics to enhance customer relationship.","priority":"high","rationale":"Resolving critical support issues could improve customer satisfaction and prospects for contract renewal."},{"action":"Resolve analytic reporting issues for British Telecommunications (EE).","priority":"medium","rationale":"Transparent and accurate reporting is critical for maintaining client trust and satisfaction."},{"action":"Support Airbnb in developing a robust engagement strategy.","priority":"high","rationale":"Improving engagement strategies is essential for maintaining client satisfaction and growth potential."}],"dependenciesAndCrossTeamNeeds":[{"impact":"Critical support ticket resolution impacting customer satisfaction and contract renewals","project":"STMicroelectronics","dependency":"Engineering support","requiredSupport":"Immediate engineering collaboration to prioritize and resolve outstanding tickets."}]}}', '27', '2026-03-24T12:29:51.914528') ON CONFLICT DO NOTHING;
