INSERT INTO "weekly_reports" ("id", "project_id", "lead_id", "week_start", "health_status", "progress", "challenges", "next_week", "team_member_feedback", "submitted_at", "status", "submitted_by_lead_id", "ai_draft_status") VALUES ('1b0560d3-65ca-47d5-bda7-8ffd83b2f41b', 'a0cc35f4-e09f-49a1-a4cb-74b0b9d2e650', '984f02e1-aa26-4d73-a714-6502e19262fa', '2026-03-16', 'at-risk', 'Customer call with Ryan was held on March 19 to discuss renewal status and reporting expectations. Following the call, a detailed reporting brief was shared with Shajee and Federico — covering Ryan''s requirements around the tracker, metrics collection, reporting depth, and cadence. Shajee and Federico synced to align on the reporting approach, incorporating structure from other account reports. A first draft of the report template and approach was requested by Monday. Timelines for a March report delivery (~10 days) were confirmed with Ryan.', 'Renewal confirmation remains pending, which is creating uncertainty around the engagement continuity.', 'Review Shajee''s report template draft and provide feedback on formatting — colour palette and logo need to align with Meta standards. Once reviewed, share the template with Ryan for feedback. Continue moderation operations and track Discord community sentiment, which has been heavily negative following Meta''s VR shutdown announcement.', NULL, '2026-03-24T11:33:42.721726', 'submitted', '984f02e1-aa26-4d73-a714-6502e19262fa', NULL) ON CONFLICT DO NOTHING;
